public class Frame {

    @Id
    private String id;

    @Indexed(unique = true)
    private String frameReference;

    private Location location;
    private Site site;
    private FrameFormat format;
    private Commercials commercials;
    private Lifecycle lifecycle;
    private ExternalRefs externalRefs;

